/* eslint-disable no-param-reassign */
import { CanvasParticle2D, random, range } from '@kyokuya/particle-helper'

interface Bubble {
  x: number
  y: number
  alpha: number
  scale: number
  velocity: number
}

// eslint-disable-next-line @typescript-eslint/no-empty-interface
export interface ParticleEffectBubbleProps {}

/**
 * Bubble
 */
export class ParticleEffectBubble extends CanvasParticle2D {
  protected readonly bubbles: Bubble[]

  constructor(container: HTMLElement, options: ParticleEffectBubbleProps = {}) {
    super(container)

    const { width, style } = this.canvas
    style.zIndex = '-1'

    const numOfBubbles = Math.ceil(width * 0.6 * Math.max(1.0, width / 1366))
    this.bubbles = this.createRandomBubbles(numOfBubbles)
  }

  /**
   * Render the contents of the current frame on the canvas.
   */
  protected override draw(): void {
    const { context } = this
    const { width, height } = this.canvas

    const velocityRatio = height / 600
    const alphaVelocity = 0.0005 * velocityRatio
    const scaleVelocity = 0.0005 * velocityRatio
    const TwoPi = 2 * Math.PI

    context.clearRect(0, 0, width, height)
    for (const bubble of this.bubbles) {
      if (bubble.alpha <= 0) this.initBubble(bubble, width, height)
      bubble.y -= bubble.velocity
      bubble.alpha -= alphaVelocity
      bubble.scale += scaleVelocity
      context.beginPath()
      context.arc(bubble.x, bubble.y, bubble.scale * 10, 0, TwoPi, false)
      context.fillStyle = 'rgba(255,255,255,' + bubble.alpha + ')'
      context.fill()
    }
  }

  /**
   * Create random bubbles.
   * @param n
   * @returns
   */
  protected createRandomBubbles(n: number): Bubble[] {
    const { width, height } = this.canvas
    return range(n).map(
      (): Bubble => ({
        x: Math.random() * width,
        y: height * (1 - Math.random() * 0.4),
        alpha: Math.random() * 0.2,
        scale: Math.random() * 0.2,
        velocity: random(0.5, 2),
      }),
    )
  }

  /**
   * Init / Reset bubble properties.
   * @param bubble
   * @param width
   * @param height
   */
  protected initBubble(bubble: Bubble, width: number, height: number): void {
    bubble.x = Math.random() * width
    bubble.y = height + random(-80, 20)
    bubble.alpha = 0.3 + Math.random() * 0.3
    bubble.scale = 0.1 + Math.random() * 0.3
    bubble.velocity = random(0.5, 2)
  }
}

export default ParticleEffectBubble
