import React from 'react'
import type { PostLayoutAction } from './actions'
import type { PostLayoutContextData } from './state'
import { initialPostLayoutContextData } from './state'

/**
 * Side-effect funcs provided by the PostLayoutContext.
 */
export interface PostLayoutContextState extends PostLayoutContextData {
  /**
   * Update the context data.
   */
  dispatch: React.Dispatch<PostLayoutAction>
}

/**
 * Create post layout context.
 */
export const PostLayoutContext: React.Context<PostLayoutContextState> =
  React.createContext({
    ...initialPostLayoutContextData,
    dispatch: (): never => {
      throw new Error(`No available dispatch prepared yet.`)
    },
  } as PostLayoutContextState)
