import loadable from '@loadable/component'
import type { EcmaImport } from '@yozora/ast'
import {
  YozoraImagePreviewer,
  YozoraMarkdownContextProvider,
} from '@yozora/react-markdown'
import type { YozoraMarkdownContextProviderProps } from '@yozora/react-markdown'
import React from 'react'
import { useCodeRunners } from './code-runner/runner'
import { defaultCustomRendererMap } from './renderer'

const Viewer = loadable(() => import('react-viewer')) as any

export interface MarkdownContextProviderProps
  extends YozoraMarkdownContextProviderProps {
  /**
   * Dynamic ecma imports.
   */
  ecmaImports: EcmaImport[]
}

export function MarkdownContextProvider(
  props: MarkdownContextProviderProps,
): React.ReactElement {
  const {
    ecmaImports,
    children,
    customRendererMap,
    codeRunners: customCodeRunners,
    ...restProps
  } = props

  const _codeRunners = useCodeRunners(ecmaImports)
  return (
    <YozoraMarkdownContextProvider
      {...restProps}
      codeRunners={customCodeRunners ?? _codeRunners}
      customRendererMap={customRendererMap ?? defaultCustomRendererMap}
    >
      {children}
      <YozoraImagePreviewer ImageViewer={Viewer} />
    </YozoraMarkdownContextProvider>
  )
}

export default MarkdownContextProvider
