import debounce from '@kyokuya/_shared/util/debounce'
import { useLocation } from '@reach/router'
import { useEffect, useMemo, useState } from 'react'

/**
 * Find the activated identifier.
 *
 * @param scrollContainer   scroll container element
 * @param anchorClassName   the CSS class name of anchor elements
 * @param viewportTopOffset the current upper boundary offset of the viewport
 */
export default function useActivatedIdentifier(
  anchorClassName: string,
  viewportTopOffset: number,
  identifierAttrName = 'id',
): {
  activatedIdentifier: string | null
  refreshActivatedIdentifier(): void
  pauseWatchingScroll(timeout: number): void
} {
  const { hash } = useLocation()
  const [activatedIdentifier, setActivatedIdentifier] = useState<string | null>(
    () => (hash == null ? null : hash.slice(1)),
  )

  // Jump to the anchor when page loaded
  useEffect(
    (): void => {
      if (activatedIdentifier == null) return
      const target = document.getElementById(activatedIdentifier)

      if (target == null) return
      target.scrollIntoView()
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [],
  )

  const { onScroll: refreshActivatedIdentifier, pauseWatchingScroll } =
    useMemo(() => {
      const topOffset = viewportTopOffset - 5
      let shouldIgnore = false

      const pauseWatchingScroll = (timeout: number): void => {
        shouldIgnore = true
        setTimeout(() => {
          shouldIgnore = false
        }, timeout)
      }

      const onScroll = debounce(function (): void {
        if (shouldIgnore) return
        const anchor = findFirstVisibleHeadingAnchor(anchorClassName, topOffset)
        if (anchor == null) return
        const nextIdentifier = anchor.getAttribute(identifierAttrName)

        if (nextIdentifier != null) setActivatedIdentifier(nextIdentifier)
      }, 50)

      return { onScroll, pauseWatchingScroll }
    }, [anchorClassName, viewportTopOffset, identifierAttrName])

  return {
    activatedIdentifier,
    refreshActivatedIdentifier,
    pauseWatchingScroll,
  }
}

/**
 * Find the first visible heading anchor.
 * @param anchorClassName
 * @param viewportTopOffset
 * @returns
 */
export function findFirstVisibleHeadingAnchor(
  anchorClassName: string,
  viewportTopOffset: number,
): Element | null {
  const anchors: HTMLCollectionOf<Element> =
    document.getElementsByClassName(anchorClassName)

  for (let i = 0; i < anchors.length; ++i) {
    const anchor = anchors[i]

    // Found an anchor under viewport top.
    if (anchor.getBoundingClientRect().top >= viewportTopOffset) return anchor
  }

  // Highlight the last anchor found if no anchor under viewport top.
  // (ie we are at the bottom of the page)
  return anchors[anchors.length - 1]
}
